// Script Continued Below
//  RAJ new functions called by client and server events.
// this keeps all of the code and logic in one place
var UserInfoScripts = Class.create();
// STRY0129041 - format for this is "rolename = key and field name in the member table is value"
// STRY0131148 - moved the table for personal permissions and changed names 
// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
//											Updated loadPhotoInfo() to use sys_user; Added getConnectEnabled();
//											in loadProfileInfo() added mobilePhone, contactPageHref, photo, emailSubject, buttonText and icons;
//											Changed phone to businessPhone
// 2.8 | 2022-03-24 | mmcc | STRY0115677 - Org Hierarchy Full Screen- Process Request Indicator- Popover Styling
//											loadProfileInfo() var userProfile deleted unused fields
//											_setStyleBackgroundImage(photo) as calling with 2nd param asBackgroundImage
// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
//											Cleaned up getConnectEnabled(); Added object pages; 
//											Removed emailSubject and buttonText as they will added to the pages object
UserInfoScripts.CONST_ARRAY_GLOBAL_ROLES_MEMBER_TABLE_MAPPING = {
	'x_153465_discovert.tasker_user': '',
	'x_153465_discovert.tasker_process_template_user': 'has_personal_template_rights',
	'x_153465_discovert.Task_Executive': 'is_task_executive',
	'x_153465_discovert.tasker_global_Tasking_Authority_member_admin' : 'is_task_administrator',
	'x_153465_discovert.tasker_process_template_global': 'can_manage_global_template',
	'x_153465_discovert.tasker_process_template_admin': 'can_manage_template_permissions',
	'x_153465_discovert.tasker_organizational_admin': 'is_global_hierarchy_administrator',
	'x_153465_discovert.tasker_application_admin': 'is_tasker_application_administrator',
	'admin': ''
	}
;
UserInfoScripts.prototype = {
	initialize: function() {
	},

	// STRY0135276 
	loadPhotoInfo: function(userGUID, asBackgroundImage) {
		var strFirstName = '';
		var strLastName = '';
		var photo;
		var displayName = '';
		var isUserOoO = false;
		var photoInfo = {
			name: '',
			photo: undefined
		};
		// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; was GlideRecord("live_profile");
		var grProfile = new GlideRecord("sys_user");
		if (grProfile.get(userGUID)) {
			// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; was .getDisplayValue("photo");
			photo = grProfile.getValue("avatar");
			// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; was if (photo.length > 0) {
			if (photo != undefined) {
				photo = photo + '.iix?t=small';
			}
			displayName = grProfile.getValue('name');
			if(asBackgroundImage){
				// if it is a background image set to background image
				if (photo == undefined) {
					photo = "Profile16.svg";
				}

				photo = this._setStyleBackgroundImage(photo);
			}
			photoInfo.photo = photo;
			photoInfo.name = displayName;
			photoInfo.sys_id = userGUID;

			isUserOoO = new Out_of_Office().isUserOutOfOffice(userGUID);
			photoInfo.isOoO = isUserOoO;
		}
		return photoInfo;
	},

	// STRY0114453  - STRY0135276 
	loadProfileInfo: function(userGUID) {
		var userProfile = {
			sys_id: userGUID,
			name: '',
			first_name: '',
			last_name: '',
			middle_name: '',
			email: '',
			businessPhone: '',
			mobilePhone: '',
			location: '',
			time_zone: '',
			contactPageHref: '',
			photo: '',
			connectEnabled: '',
			liveProfileId: '',
			messages: {},
			icons: {}
		};

		var grUser = new GlideRecord('sys_user');
		if(grUser.get(userGUID)){
			// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; 
			//  added getDisplayValue to many, .contactPageHref, mobile phone; Changed phone to businessPhone, add call to get Connect Chat fields
			userProfile.name = grUser.getDisplayValue('name');
			userProfile.first_name = grUser.getDisplayValue('first_name');
			userProfile.last_name = grUser.getDisplayValue('last_name');
			userProfile.middle_name = grUser.getDisplayValue('middle_name');
			userProfile.email = grUser.getDisplayValue('email');
			userProfile.businessPhone = grUser.getDisplayValue('phone');
			userProfile.mobilePhone = grUser.getDisplayValue('mobile_phone');
			userProfile.location = grUser.getDisplayValue('location');
			userProfile.contactPageHref = '?id=user_profile&sys_id=' + userGUID;

			// if no user time zone, but location is loaded
			if(grUser.time_zone){
				userProfile.time_zone = grUser.getDisplayValue('time_zone'); // + '';
			} else if(grUser.location && grUser.location.time_zone){
				userProfile.time_zone = gs.getMessage("Tasker - (location) - ") + userProfile.location.time_zone;
			}
			// Connect Chat 
			var chat = this.getConnectEnabled(userGUID);
			userProfile.connectEnabled = chat.connectEnabled;
			userProfile.liveProfileId = chat.liveProfileId;
		}
		return userProfile;
	},

	// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; 
	// Get info about the plugin being active and if live_profile has a record get the live profile ID for the useer
	getConnectEnabled: function(userId) {
		var chat = {
			connectEnabled: false,
			liveProfileId: ''
		};

		// is chat active?
		chat.connectEnabled = GlidePluginManager().isActive('com.glide.connect');

		// Check if logged in user has a live profile for sending connect messages
		if (GlidePluginManager().isActive('com.glideapp.live_common')) {
			var liveProfileGR = new GlideRecord("live_profile");
			liveProfileGR.addQuery("document", userId);
			liveProfileGR.query();
			if (liveProfileGR.next()) {
				chat.liveProfileId = liveProfileGR.getValue("sys_id");
// 				data.liveProfileModel = $sp.getForm("live_profile", data.liveProfileID)._fields;
// 				// live_profile short_description is shown here as "Bio", so popup label/hint must reflect that
// 				if (data.liveProfileModel.short_description) {
// 					data.liveProfileModel.short_description.label = gs.getMessage("Bio");
// 					data.liveProfileModel.short_description.hint = gs.getMessage("Biography");
// 				}
			} else {
				chat.connectEnabled = false; // can't find a live profile for this user, so lets not integrate Connect
			}
		}

		return chat;
	},

	// Returns a string to set a style tag over in the HTML to  display a persons' photo
	// Parameter photo is sys_user avatar field with .iix?t=small appended
	_setStyleBackgroundImage: function(photo) {
		var imageUrl = '';
		imageUrl = "background-image: url('" + photo + "');";
		return imageUrl;
	},

	// STRY0129039 -  STRY0129041
	getUserGlobalRolesAndMessages: function(userId){
		var tsss = new tasking_System_Settings_Scripts();
		var l_taskRoleGroups = tsss.loadGlobalRolesForGroupsSettings();

		var lUserId = "";
		var grRole;
		var role;
		var hasRole = false;
		var arrRoles = [];
		var arrUserPermissions = [];
		// if passed use the user id, if not use the current user
		lUserId = userId? userId : gs.getUserID();
		arrRoles = tasking_System_Settings_Scripts.CONST_ARRAY_ALL_GLOBAL_ROLES;
		for(var i=0; i<arrRoles.length; i++){
			role = arrRoles[i];
			var taskRoleGroup = l_taskRoleGroups[role];
			var objUserRole = {"role": role,
								"fieldName": UserInfoScripts.CONST_ARRAY_GLOBAL_ROLES_MEMBER_TABLE_MAPPING[role],
								"groupName": "",
								"hasRole": false,
								"hasRoleExplicitly": false,
								"usesGroupsForRoles": l_taskRoleGroups.uses_groups_for_roles};
			grRole = new GlideRecord('sys_user_has_role');
			grRole.addQuery('user', lUserId);
			grRole.addQuery('role.name', role);
			grRole.query();
			if (grRole.next()) {
				objUserRole.hasRole = true;
				if(!grRole.inherited){
					objUserRole.hasRoleExplicitly = true;
				}
			}
			if(l_taskRoleGroups.uses_groups_for_roles && taskRoleGroup){
				objUserRole.groupSelected = taskRoleGroup.validation.groupSelected;
				objUserRole.groupHasRole = taskRoleGroup.validation.groupHasRole;
				if(taskRoleGroup.validation.groupSelected){
					objUserRole.groupName = taskRoleGroup.value.displayValue;
				}

			}
			arrUserPermissions.push(objUserRole);
		}
		return arrUserPermissions;
	},

	// DFCT0010296 - if the member was removed from thier default OU, set another default OU
	setNewDefaultOU: function(member_userid){
		var newDefaultOU = '';
		var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMembers.addQuery('office_member', member_userid);
		grMembers.query();
		// get the first OU alphabetically and set that to the default
		if(grMembers.next()){
			newDefaultOU = grMembers.discover_office_hierarchy;

		} else {
			// if no member records left, clear the default OU.
			newDefaultOU='';
		}
		// STRY0131148 move to org User table
		var grOrgUser = new GlideRecordSecure('x_153465_discovert_organization_user');
		grOrgUser.addQuery('u_tasker_user', member_userid);
		grOrgUser.query();
		if(grOrgUser.next()){
			// this is the first ou found alphabetically 
			grOrgUser.u_default_ou = newDefaultOU;
			grOrgUser.update();
		}	
	},

	getAllTopOUsForUser: function(userId){
		var topOUs = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		// DFCT0011930 - DFCT0011967 - DFCT0011988 - DFCT0011990 DFCT0011994
		grOUs.addQuery('office_member', userId);
		grOUs.query();
		while(grOUs.next()){
			topOUs.push(grOUs.getValue('u_top_ou'));
		}
		if (topOUs.length > 0){
			var au = new global.ArrayUtil();
			topOUs = au.unique(topOUs);
		}
		return topOUs;
	},

	// STRY0114396
	getUserOffices: function(user){
		var offices = [];
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grOUs.addQuery('office_member', user);
		grOUs.query();
		while(grOUs.next()){
			offices.push(grOUs.getValue('discover_office_hierarchy'));
		}
		if (offices.length > 0){
			var au = new global.ArrayUtil();
			offices = au.unique(offices);
		}
		return offices;  
	},

	// STRY0095102 - by using a single method that checks properties in all the places we load restricted groups, updates can be made from one place
	getRestrictedGroupsAndDescendents: function(groupName){
		var groups = groupName + '';
		groups = this.getNestedDescendantGroups(groups);
		return groups;
	},		

	// STRY0095102 - get the nest list of groups
	getNestedDescendantGroups: function(restricted_group){
		// if not valid restricted group, return it
		if(restricted_group != undefined && restricted_group != ''){
			var groupGiven = new GlideRecord('sys_user_group');
			groupGiven.addQuery('parent',restricted_group);
			groupGiven.query();
			while(groupGiven.next()){
				restricted_group += "," + this.getNestedDescendantGroups(groupGiven.getUniqueValue());
			}
		}
		return restricted_group;
	},

	// STRY0085438
	IsUserOUTA: function(userId, ou){
		var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMembers.addQuery('discover_office_hierarchy', ou);
		grMembers.addQuery('office_member' , userId);
		grMembers.addQuery('office_task_authority', 'true');	
		grMembers.query();


		if(grMembers.next()){
			return true;
		}else{
			return false;
		}
	},

	// STRY0076016
	UserHasRole: function(roleName)
	{
		return gs.getUser().hasRole(roleName);
	},	

	// DFCT0011930 
	userIsOrgAdminForOU: function(ouID){
		var answer = false;
		var role = 'x_153465_discovert.tasker_organizational_admin';
		answer = this._userIsAdminInOrgStructure(ouID, role);
		return answer;
	},

	// DFCT0011930 
	userIsTaskAdministratorForOU: function(ouID){
		var answer = false;
		var role = 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin';
		answer = this._userIsAdminInOrgStructure(ouID, role);

		return answer;
	},

	// DFCT0011930 
	userIsTaskExecutiveForOU: function(ouID){
		var answer = false;
		// DFCT0011964 - had the wrong wrole
		var role = 'x_153465_discovert.Task_Executive';
		answer = this._userIsAdminInOrgStructure(ouID, role);

		return answer;
	},

	// DFCT0011930 
	_userIsAdminInOrgStructure: function (ouID, role){
		var answer = false;
		var taskPrivacy = new task_privacy();
		var currentUser = gs.getUserID();

		var userHasRoleTAA = this.UserHasRole('x_153465_discovert.tasker_application_admin');
		var userHasRole = this.UserHasRole(role);
		var userIsInOrgStructure = taskPrivacy.userIsInOrgStructureForOU(ouID,currentUser);

		answer =  userHasRoleTAA || (userHasRole && userIsInOrgStructure);

		return answer;

	},

	// STRY0076016 - DFCT0011765
	userCanWriteMem_field_office_task_authority: function(ouID){
		// DFCT0011930 
		var answer = this.userIsOrgAdminForOU(ouID);		
		return answer;
	},

	// STRY0076016 - DFCT0011765 - DFCT0011930
	userCanWriteMem_field_is_office_administrator: function(ouID){
		var answer = false;
		var currentUser = gs.getUserID();
		var isUserGHAforOU = this.userIsOrgAdminForOU(ouID);
		var userHasRoleTAA = this.UserHasRole('x_153465_discovert.tasker_application_admin');
		var isUserOUAdmin = this.IsUserOUAdministrator(ouID, currentUser);
		answer =  userHasRoleTAA || isUserGHAforOU || isUserOUAdmin;

		return answer;
	},

	// STRY0076016 - DFCT0011930
	userCanWriteMem_field_can_manage_ou_members: function(ouID){
		var answer = false;
		var currentUser = gs.getUserID();
		var userHasRoleTAA = this.UserHasRole('x_153465_discovert.tasker_application_admin');
		var isUserGHAforOU = this.userIsOrgAdminForOU(ouID);
		var isUserOUAdmin = this.IsUserOUAdministrator(ouID, currentUser);
		var isUserMemberAdmin = this.IsUserMemberAdministrator(ouID, gs.getUserID());
		answer = isUserGHAforOU || userHasRoleTAA ||  isUserOUAdmin || isUserMemberAdmin;

		return answer;
	},

	// STRY0076016 - DFCT0011930
	// this is used to set the row level write
	userCanWriteMem: function(ouID){
		var answer = false;
		var currentUser = gs.getUserID();
		// DFCT0010580 - if ouID not set, then return false
		if(ouID && ouID != ''){
			var isUserGHAforOU = this.userIsOrgAdminForOU(ouID);
			var userHasRoleTAA = this.UserHasRole('x_153465_discovert.tasker_application_admin');
			var isUserOUAdmin = this.IsUserOUAdministrator(ouID, currentUser);
			var isUserTaskAdminforOU = this.userIsTaskAdministratorForOU(ouID);
			var isUserTemplateAdministrator = this.UserHasRole('x_153465_discovert.tasker_process_template_admin');
			var isUserMemberAdmin = this.IsUserMemberAdministrator(ouID, currentUser);

			answer = isUserGHAforOU || userHasRoleTAA || isUserTaskAdminforOU || isUserTemplateAdministrator ||  isUserOUAdmin || isUserMemberAdmin;
		}
		return answer;
	},

	// STRY0076016 - DFCT0011930
	// this is used to set the Add and Delete ACLs
	userCanCreateMem: function(ouID){
		var answer = false;
		var currentUser = gs.getUserID();
		var isUserGHAforOU = this.userIsOrgAdminForOU(ouID);
		var isUserOUAdmin = this.IsUserOUAdministrator(ouID, currentUser);
		var isUserMemberAdmin = this.IsUserMemberAdministrator(ouID, currentUser);
		// DFCT0010580 - if ouID not set, then return false
		if(ouID && ouID != ''){
			answer = isUserGHAforOU || isUserOUAdmin || isUserMemberAdmin;
		}
		return answer;
	},

	// STRY0050440 - DFCT0011930
	userCanWriteOU: function(ouID){
		var answer = false;
		var currentUser = gs.getUserID();
		var isUserGHAforOU = this.userIsOrgAdminForOU(ouID);
		var isUserOUAdmin = this.IsUserOUAdministrator(ouID, currentUser);
		answer = isUserGHAforOU || isUserOUAdmin;		

		return answer;
	},

	// STRY0050440 - DFCT0011930
	userCanCreateOU: function(ouID){
		var answer = false;
		var currentUser = gs.getUserID();
		var isUserGHAforOU = this.userIsOrgAdminForOU(ouID);
		var isUserOUAdmin = this.IsUserOUAdministrator(ouID, currentUser);
		answer = isUserGHAforOU || isUserOUAdmin;
		return answer;
	},

	// STRY0079396
	userIsOUTemplateDesigner: function()
	{
		var answer = false;
		var grMembers = new GlideAggregate('x_153465_discovert_discover_office_members');
		grMembers.addQuery('office_member', gs.getUserID());
		grMembers.addQuery('has_ou_process_rights', true);
		grMembers.addAggregate('COUNT');
		grMembers.query();

		if(grMembers.next()){

			if (grMembers.getAggregate('COUNT') > 0){
				answer = true;
			}
		}
		return answer;
	},

	// DFCT0011930 - STRY0131148 - this is used to determine if the user can create/write/delete from the Organizational Users table
	userCanWrite_organizational_members_table: function(){
		var answer = false;
		var ouID = current.discover_office_hierarchy;
		var currentUser = gs.getUserID();
		var isUserGHAforOU = this.userIsOrgAdminForOU(ouID);
		var userHasRoleTAA = this.UserHasRole('x_153465_discovert.tasker_application_admin');
		var userIsOfficeAdminOrMemberAdimn = this.userHasRoleOUHieararchyAdminOrOUMember(currentUser);

		answer =  isUserGHAforOU || userHasRoleTAA || userIsOfficeAdminOrMemberAdimn;
		return answer;		
	},

	// STRY0131148 - this is used to determine if the user can create/write/delete from the Organizational Users table
	userHasRoleOUHieararchyAdminOrOUMember: function(userID){
		var answer = false;
		var grMembers = new GlideAggregate('x_153465_discovert_discover_office_members');
		grMembers.addQuery('office_member', gs.getUserID());
		grMembers.addQuery('can_manage_ou_members', true).addOrCondition('is_office_administrator',true);
		grMembers.addAggregate('COUNT');
		grMembers.query();

		if(grMembers.next()){
			if (grMembers.getAggregate('COUNT') > 0){
				answer = true;
			}
		}
		return answer;		
	},

	// STRY0050440
	IsUserOUAdministrator: function(ouID,userID)
	{
		var answer = false;
		// STRY0059849 - use new method that looks for the OUHA responsible, then checks to see if this user is in the list
		var ouHA_responsible = new OrganizationalScripts().getOUHA_responsible(ouID);
		// OUHA_responsible = {OU:{value:'', displayValue:''}, Administrators: {value:'', displayValue: ''}};
		answer = (ouHA_responsible.Administrators.value.indexOf(userID)>-1);

		return answer;
	},

	// DFCT0011930
	isUserOrgAdminForUser: function(user){
		var answer = false;
		var OUID;
		var isUserGHAforOU;
		var grOUs = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grOUs.addQuery('office_member', user);
		grOUs.query();
		while(grOUs.next()){
			OUID = grOUs.getValue('discover_office_hierarchy');
			isUserGHAforOU = this.userIsOrgAdminForOU(OUID);
			if(isUserGHAforOU){
				answer = true;
				break;
			}
		}
		return answer;  
	},

	// STRY0131148 - DFCT0011930
	canChangeUserDefaultOU: function(ORG_User_Sys_Id, userID)
	{
		var answer = false;
		var grOrgUsers = new GlideRecordSecure('x_153465_discovert_organization_user');
		if(grOrgUsers.get(ORG_User_Sys_Id)){
			var OrgUserID = grOrgUsers.u_tasker_user;
			var isMemberUserGiven = userID == OrgUserID;
			// is the user a Global Hierarchy Admin for user
			var isOrgAdminForUser = this.isUserOrgAdminForUser(OrgUserID);
			answer = isMemberUserGiven || isOrgAdminForUser;
		}
		return answer;
	},

	// STRY0057846 - DFCT0011930
	canChangeDefaultOU: function(mem_Sys_Id, userID)
	{
		var answer = false;
		var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		if(grMembers.get(mem_Sys_Id)){
			var OUID = grMembers.discover_office_hierarchy;
			var MemID = grMembers.office_member;
			var isUserGHAforOU = this.userIsOrgAdminForOU(OUID);
			// is the user a Global Hierarchy Admin
			var isUserOUAdmin = this.IsUserOUAdministrator(OUID, userID);
			var isUserMemberAdmin = this.IsUserMemberAdministrator(OUID, userID);
			var isMemberUserGiven = userID == MemID;

			// STRY0050440 - STRY0057846
			// is this the current user or User is OU Hierarchy Admin, or OU Member Admin
			answer = isMemberUserGiven || isUserOUAdmin || isUserMemberAdmin;
		}
		return answer;
	},

	// RJ STRY0073150
	// TemplateInstance needs a special process right check.  
	// The Instance create needs to be able to receive the ID of the Template being started.
	userHasProcessRunRights: function(templateId)
	{
		if(!templateId) return false;

		var userHasTemplateRights = false;
		var grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
		if(grTemp.get(templateId)){
			userHasTemplateRights = this.userHasProcessRights(grTemp);
		}
		return userHasTemplateRights;
	},



	// KT - RLS - STRY0065050: 03/20/2020
	UserHasRoleScoped: function(roleName, userId)
	{
		var hasRole = false;
		// Check if the user has role. The OOTB fuction hasRole() only works for current user and the GetUserId() to try to check the role from a giver user only work for GLOBAL apps and no for SCOPEP apps.
		var grRole = new GlideRecord('sys_user_has_role');
		grRole.addQuery('role.name', roleName);
		grRole.addQuery('user', userId);
		grRole.query();
		if (grRole.next()) {
			hasRole = true;
		}

		return hasRole;
	},

	// DFCT0011928
	userHasGlobalProcessRightsPrivacyFiltered: function(primary_office){
		answer = false;
		var userHasGlobalTemplateRights = this.UserHasRole('x_153465_discovert.tasker_process_template_global');
		userHasGlobalTemplateRights = userHasGlobalTemplateRights == true || userHasGlobalTemplateRights == 'true';
		var isUserInOrgStructure = new task_privacy().isUserInOrgStructure(primary_office, gs.getUserID());
		answer = userHasGlobalTemplateRights && isUserInOrgStructure;
