	userHasOUProcessRightsOnAnOU: function(ou){
		var userHasProcessRights = false;
		// user needs the OU role. 
		// technically, the user should not be able to have this role without also being in the table below.
		// we are going to check both b/c some table acls might be based on this role
		var currentUser = gs.getUserID();
		var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMembers.addQuery('office_member' , currentUser);
		// STRY0073150 - RAJ TODO - this is temporary, once you get ADMIN permissions to update ACLs, remove the if statement.
		if(ou){
			// STRY0073150 the user must have rights in the office provided
			grMembers.addQuery('discover_office_hierarchy',ou);
		}
		// STRY0073150
		var procQueryCond = grMembers.addQuery('has_ou_process_rights', true);
		// STRY0073150 - also look to see if the member is a Tasm manager of the OU
		procQueryCond.addOrCondition('office_task_authority', true);

		grMembers.query();

		if(grMembers.next()){
			userHasProcessRights = true;
		}else{
			userHasProcessRights = false;
		}
		return userHasProcessRights;
