		// if user lost porcess rights, they can't edit the process
		if(this.UserHasRole('x_153465_discovert.tasker_process_template_user')){
			// And, the user owns this process
			if(userID == processOwner){
				userHasProcessRights = true;
			}
		}
		// TODO, RAISE TO PRODUCT OWNERS... CAN ANYONE OTHER THAN THE PROCESS OWNER EDIT A PERSONAL PROCESS?
		// CAN THE OWNERS ADMIN, THE OU PROCESS ADMIN OF THE USERS DEFAULT OUT?
		// NEED TO MAKE A DECISION WHO ELSE COULD DO THIS...  OR, WE NEED TO DECIDE WHO CAN CHANGE THE PROCESS OWNER FIELD.
		return userHasProcessRights;
	},

	userHasProcessRights: function(gr)
	{
		var recordTable = gr.getTableName();
		var userHasProcessRights = false;
		var processLevel;
		// DFCT0011973
		var primary_office;
		var processOU;
		var processOwner;
		// STRY0095102 - change this to check against this users list of groups rather than looking for the user in the group
		var groupsArray;

		var restrictedGroup = '';
		if (recordTable == 'x_153465_discovert_discover_routing_template'){
			// DFCT0011973
			primary_office = gr.getValue("u_primary_office");
			// get the process owner
			processOwner = gr.process_owner;
			// Get the process Level
			processLevel = gr.process_level;
			// Get the Process OU
			processOU = gr.process_ou;
			// Get the Restricted Group
			restrictedGroup = gr.getValue('u_restricted_group');
		} else if(recordTable == 'x_153465_discovert_route_tasks'){
			// DFCT0011973
			primary_office = gr.getValue("primary_office");
			// get the process owner
			processOwner = gr.tasker_process_definition.process_owner;
			// Get the process Level
			processLevel = gr.tasker_process_definition.process_level;
			// Get the Process OU
			processOU = gr.tasker_process_definition.process_ou;
			// Get the Restricted Group
			restrictedGroup = gr.getValue('assigned_to_group'); 
		} else if (recordTable == 'x_153465_discovert_discover_routing_runtime'){
			// DFCT0011973
			primary_office = gr.getValue("u_primary_office");
			// get the process owner
			processOwner = gr.routing_template_ref.process_owner;
			// Get the process Level
			processLevel = gr.routing_template_ref.process_level;
			// Get the Process OU
			processOU = gr.routing_template_ref.process_ou;
			// Get the Restricted Group
			restrictedGroup = gr.getValue('u_restricted_group');
		} else if (recordTable == 'x_153465_discovert_tasker_schedule'){
			// DFCT0011973
			primary_office = gr.tasker_process.u_primary_office;
			// STRY0079396 - schedule was using Template OU Designer in a call, not the update mechansim
			// get the process owner
			processOwner = gr.tasker_process.process_owner;
			// Get the process Level
			processLevel = gr.tasker_process.process_level;
			// Get the Process OU
			processOU = gr.tasker_process.process_ou;
		}
		restrictedGroup = restrictedGroup == null ? '': restrictedGroup;
		// STRY0074534 - Template Admins can see and change any template, but not run them
		if(this.userHasProcessTemplateAdminRights()){
			if(restrictedGroup == ''){
				return true;
			} else{
				// STRY0095102 - change this to check against this users list of groups rather than looking for the user in the group
				groupsArray = gs.getUser().getMyGroups().toString().split(",");
				return groupsArray.indexOf(restrictedGroup) !== -1;
				// return gs.getUser().isMemberOf(restrictedGroup);
			}
		}
		switch (processLevel.toString()){
			case 'global_process': 
				// DFCT0011973
				userHasProcessRights = this.userHasGlobalProcessRightsPrivacyFiltered(primary_office);
				break;
			case 'ou_process':
				userHasProcessRights = this.userHasOUProcessRights(processOU);
				break;
			case 'my_process':
				var userID = gs.getUserID();
				userHasProcessRights = this.userHasPersonalProcessRightsForProcess(processOwner, userID);
				break;
		}

		if (userHasProcessRights){
			if(restrictedGroup != ''){
				// STRY0095102 - change this to check against this users list of groups rather than looking for the user in the group
				groupsArray = gs.getUser().getMyGroups().toString().split(",");
				userHasProcessRights = groupsArray.indexOf(restrictedGroup) !== -1;
			}
		}
		return userHasProcessRights;
	},

	//KTORRES: STRY0014160
	checkMemberinInGroup: function(member, assignment_group) {

		var userBelongstoGroup = false;
		var users = new GlideRecord('sys_user_grmember');  
		users.addQuery('user','=', member);
		// STRY0095102 - Use IN instead of equals to pull members from all parent groups
		users.addQuery('group','IN', assignment_group);
		users.query();  

		while (users.next())	{  
			userBelongstoGroup = true;
		}

		return userBelongstoGroup;

	},

	// STRY0078831
	getAllMembersSysIdsInGroup: function(groupName) {
        var memArr = [];

		// STRY0095102 - by using a single method that checks properties in all the places we load restricted groups, updates can be made from one place
		var groups = this.getRestrictedGroupsAndDescendents(groupName);
        var grUsers = new GlideRecord('sys_user_grmember');
		// STRY0095102 - Use IN instead of equals to pull members from all parent groups
        grUsers.addQuery('group', 'IN', groups);
        grUsers.query();
        while (grUsers.next()) {
			memArr.push(grUsers.getValue('user'));
        }
		return memArr;
	},

	// STRY0078831
	getOUsForRestrictedGroup: function(restrictedGroup) {
		var ArrRestrictedOUs = [];
		var ouMemArr = [];
		ouMemArr = this.getAllMembersSysIdsInGroup(restrictedGroup);
		var grMemberOus = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMemberOus.addQuery('office_member', 'IN', ouMemArr.join(','));
		grMemberOus.query();
		while(grMemberOus.next()){
			ArrRestrictedOUs.push(grMemberOus.getValue('discover_office_hierarchy'));
		}
		// Get External OUs with contacts
		var grOus = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		var grContactOus = new GlideRecordSecure('x_153465_discovert_organizational_contacts');
		grContactOus.addQuery('u_user_information', 'IN', ouMemArr.join(','));
		grContactOus.query();
		while(grContactOus.next()){
			if(grOus.get(grContactOus.getValue('u_contact_ou'))){
				// only add externals based on conatcts, do not add internal ous based on contacts
				if(grOus.u_external_flag==true){
					ArrRestrictedOUs.push(grOus.getUniqueValue());
				}
			}
		}
		// DFCT0010835  - deduplicate the array
		if (ArrRestrictedOUs.length > 0){
			var au = new global.ArrayUtil();
			ArrRestrictedOUs = au.unique(ArrRestrictedOUs);
		}
		return ArrRestrictedOUs;
	},

	IsUserInOU: function(ouID,userID)
	{
		var answer = false;
		//Query organizational unit members to see if the user is a member
		// RAJ - STRY0011695 - change to use Glide Aggregate
		var grMembers = new GlideAggregate('x_153465_discovert_discover_office_members');
		grMembers.addQuery('discover_office_hierarchy', ouID);
		grMembers.addQuery('office_member', userID);
		// RAJ - STRY0011695 - change to use Glide Aggregate
		grMembers.addAggregate('COUNT');
		grMembers.query();

		if(grMembers.next()){
			// RAJ - STRY0011695 - change to use Glide Aggregate
			if (grMembers.getAggregate('COUNT') > 0){
				answer = true;
			}
		}
		return answer;
	},

