	//  RAJ STSK0011104 if the user is NOT a TA, but is in the OU, they can assign themselves to the Tasker, so the user needs to be able to see the "assigned members.
	//  RAJ STSK0011104 - allow changing task assingment based on user being a tasking authority
	//  changed the script include to add a method to determine if the user is a Tasking Authority
	CanUserAssignSelfOrOthers: function(ouID,userID)
	{
		//Query organizational unit members to see if the user is a Tasking Authority for the OU
		//  RAJ STSK0011104 updated to control whether a user can assign tasks based on Tasking Authority instead of ownership of the task or membership in the OU
		// STRY0112462
		var tsss = new tasking_System_Settings_Scripts();
		if(this.IsUserTaskingAuthority(ouID,userID) || this.IsUserInOU(ouID,userID) || tsss.ouIsPermissive(ouID)){
			return true;
		}
		else{
			return false;
		}
	},
	// STRY0067125 - Check the users permissions for assigning members in a template
	CanUserAssignSelfOrOthersInTemplate: function(ouID,userID, template)
	{
		var grTemplate = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
		// STRY0072771 - Debt Certification
		if(grTemplate.get(template)){
			var templateLevel = grTemplate.getValue('process_level');
			var templateOU = '';
			// if template at OU level, the Primary Assignee needs to be same as the OU of the template being built to select users
			if(templateLevel == 'ou_process'){
				templateOU = grTemplate.getValue('process_ou');
				if(ouID == templateOU)
					return true;
				else
					return false;
			}
		}
		// if you got here, the template level is global or my.
		// In both scenarios, the user's permissions for an our drive whether the user is able to select users or not when definint templates.
		// STRY0112462
		var tsss = new tasking_System_Settings_Scripts();
		if(this.IsUserTaskingAuthority(ouID,userID) || this.IsUserInOU(ouID,userID) || tsss.ouIsPermissive(ouID)){
			return true;
		}
		else{
			return false;
		}
	},

	ManageUserRoleCheckAndAdd: function(office_member, role_name, role_id)
	{
		var roleAdded = false;
		// Add role if member does not have it
		var grRole = new GlideRecord('sys_user_has_role');
		grRole.addQuery('user', office_member);
		grRole.addQuery('role.name', role_name);
		grRole.query();
		if (!grRole.next()) {
			grRole.initialize();
			grRole.user = office_member;
			grRole.role = role_id;
			grRole.insert();
			roleAdded = true;
		}
		return roleAdded;
	},

	ManageUserRoleCheckAndDelete: function(office_member, office_member_permission_field, role_name)
	{
		var roleDeleted = false;
		// office administrator removed.  If this user is not an administrator of any other offices, the role single_ou_admin should be removed
		var grMemOUs = new GlideRecordSecure("x_153465_discovert_discover_office_members");
		grMemOUs.addQuery('office_member', office_member);

		if(office_member_permission_field != ''){
			grMemOUs.addQuery(office_member_permission_field,true);
		}

		// if no other records found, remove role
		if (!grMemOUs.next()){
			var hasRole = new GlideRecord('sys_user_has_role');
			hasRole.addQuery('user', office_member);
			hasRole.addQuery('role.name', role_name);
			hasRole.query();
			if (hasRole.next()) {
				hasRole.deleteRecord();
				roleDeleted = true;
			}
		}
		return roleDeleted;
	},
	getRoleIdByName: function(role_name) {
		var roles = new GlideRecord("sys_user_role");
		roles.addQuery("name", role_name);
		roles.query();
		if(roles.next()) {
			return roles.sys_id;
		}
		return "";
	},

	// STRY0124860 - external function calls 2 internal functions
	addRole: function(user_id, user_name, role_name){
		var roleAdded = false;
		var msgRoleAdded = gs.getMessage("Tasker - Role:{0} - added to user: {1}",[role_name, user_name]);

		if(tasking_System_Settings_Scripts.CONST_USES_GROUPS_FOR_ROLES){
			roleAdded = this._addUserToGroup(user_id, role_name);
		} else {
			roleAdded = this._addUserToRole(user_id, role_name);
		}
		if(roleAdded){
			gs.addInfoMessage(msgRoleAdded);
		}

		return roleAdded;
	},

	// STRY0124860 - called if groups are being used to manager permissions
	_addUserToGroup: function(user_id, role_name){
		var userAddedToGroup = false;
		var gr_userGroup = new GlideRecord('sys_user_grmember');
		var group_id = '';

		var msgUsesRoles = gs.getMessage("Tasker - The System Property [Uses Groups for Roles] is true,");
		var msgGroupNotDefined = gs.getMessage("Tasker - but a group is not defined for the System Property ");
		var msgUserAlreadyInGroup1 = gs.getMessage("Tasker - . The user");
		var msgUserAlreadyInGroup2 = gs.getMessage("Tasker - is already in group");
		var msgPropertyName;
		gr_userGroup.initialize();
		switch(role_name){
			case "x_153465_discovert.tasker_application_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TASKER_APPLICATION_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_tasker_application_administrator_group]';
				break;
			case "x_153465_discovert.tasker_global_Tasking_Authority_member_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TASK_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_task_administrator_group]';
				break;
			case "x_153465_discovert.Task_Executive":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TASK_EXECUTIVE_GROUP;
				msgPropertyName = '[x_153465_discovert.role_task_executive_group]';
				break;
			case "x_153465_discovert.tasker_organizational_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_HIERARCHY_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_global_hierarchy_administrator_group]';
				break;
			case "x_153465_discovert.tasker_process_template_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TEMPLATE_DESIGNER_PERMISSIONS_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_template_designer_permissioins_administrator_group]';
				break;
			case "x_153465_discovert.tasker_process_template_global":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_TEMPLATE_DESIGNER_GROUP;
				msgPropertyName = '[x_153465_discovert.role_global_template_designer_group]';
				break;
			case "x_153465_discovert.tasker_process_template_user":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_PERSONAL_TEMPLATE_DESIGNER_GROUP;
				msgPropertyName = '[x_153465_discovert.role_personal_template_designer_group]';
				break;
			case "x_153465_discovert.tasker_user":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TAKSER_USER_GROUP;
				msgPropertyName = '[x_153465_discovert.role_tasker_user_group]';
				break;
		}
		if(!group_id || group_id==""){
			msgUsesRoles = msgUsesRoles + msgGroupNotDefined + msgPropertyName;
			gs.error(msgUsesRoles);
		} else {
			// if the group id is in the system property, then add the record and return true
			gr_userGroup.addQuery('user', user_id);
			gr_userGroup.addQuery('group', group_id);
			gr_userGroup.query();
			if(gr_userGroup.next()){
				// user in group, dispaly info message
				// user not in group, dispaly info message
				msgUsesRoles = msgUsesRoles + msgUserAlreadyInGroup1 + " [" + gr_userGroup.getDisplayValue("user") + "] " +
					msgUserAlreadyInGroup2 + " [" + gr_userGroup.getDisplayValue("group") + "]";
				gs.info(msgUsesRoles);
			} else {
				// user not in group, add user to group
				gr_userGroup.initialize();
				gr_userGroup.user = user_id;
				gr_userGroup.group = group_id;
				gr_userGroup.insert();
			}
			userAddedToGroup = true;
		}
		return userAddedToGroup;
	},

	// STRY0124860 - called if roles are being used to manager permissions
	_addUserToRole: function(user_id, role_name){
		var role_id = this.getRoleIdByName(role_name);
		if(!role_id || role_id == null || role_id == '')
			return false;
		var roleAdded = false;
		// Add role if member does not have it
		var grRole = new GlideRecord('sys_user_has_role');
		grRole.addQuery('user', user_id);
		grRole.addQuery('role', role_id);
		grRole.query();
		if (!grRole.next()) {
			grRole.initialize();
			grRole.user = user_id;
			grRole.role = role_id;
			grRole.insert();
			roleAdded = true;
		}
		return roleAdded;
	},

	// STRY0131148 - Improve role changes with a function for Add/Remove
	removeAllGlobalRoles: function(user_id, user_name){
		this.removeRole(user_id, user_name,'is_tasker_application_administrator', 'x_153465_discovert.tasker_application_admin', 'GlobalRole');
        this.removeRole(user_id, user_name, 'is_task_administrator', 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin', 'GlobalRole');
        this.removeRole(user_id, user_name, 'is_task_executive', 'x_153465_discovert.Task_Executive', 'GlobalRole');
		this.removeRole(user_id, user_name, 'is_global_hierarchy_administrator', 'x_153465_discovert.tasker_organizational_admin', 'GlobalRole');
		this.removeRole(user_id, user_name, '', 'x_153465_discovert.tasker_single_ou_admin', 'GlobalRole');
		this.removeRole(user_id, user_name, '', 'x_153465_discovert.tasker_single_ou_member_admin', 'GlobalRole');
		this.removeRole(user_id, user_name, 'can_manage_template_permissions', 'x_153465_discovert.tasker_process_template_admin', 'GlobalRole');
		this.removeRole(user_id, user_name, 'can_manage_global_template', 'x_153465_discovert.tasker_process_template_global', 'GlobalRole');
		this.removeRole(user_id, user_name, 'has_ou_process_rights', 'x_153465_discovert.tasker_process_template_ou', 'GlobalRole');
		this.removeRole(user_id, user_name, 'has_personal_template_rights', 'x_153465_discovert.tasker_process_template_user', 'GlobalRole');
		this.removeRole(user_id, user_name, 'can_import_ou_hierarchy', 'x_153465_discovert.tasker_hierarchy_import_user', 'GlobalRole');
        // this user has been deleted.
        // Moved to the end so removed last when all roles that inherit it are released
        this.removeRole(user_id, user_name, '', 'x_153465_discovert.tasker_user', 'GlobalRole');
	},


	removeRole: function(user_id, user_name, field, role_name, role_type){
		var roleDeleted = false;
		var msgRoleRemoved = gs.getMessage("Tasker - Role:{0} - removed from user: {1}",[role_name, user_name]);
		// the first iteration of groups only uses groups for global roles
		if(tasking_System_Settings_Scripts.CONST_USES_GROUPS_FOR_ROLES && role_type == 'GlobalRole'){
			roleDeleted = this._removeUserFromGroup(user_id, field, role_name, role_type);
		} else {
			roleDeleted = this._removeUserFromRole(user_id, field, role_name, role_type);
		}	
		if(roleDeleted){
			gs.addInfoMessage(msgRoleRemoved);
		}
		return roleDeleted;
	},
	_removeUserFromRole: function(user_id, field, role_name, role_type)
	{
		//KT: RoleType = GlobalRole i.e GlobalTasking Authority
		var role_id = this.getRoleIdByName(role_name);
		if(!role_id || role_id == null || role_id == '')
			return false;

		var roleDeleted = false;
		var roleShoulbBeDeleted = false;

		if (role_type == 'GlobalRole') roleShoulbBeDeleted = true;

		if (role_type == 'OURole') {
			var grMemOUs = new GlideRecordSecure("x_153465_discovert_discover_office_members");
			grMemOUs.addQuery('office_member', user_id);
			if(field != '') grMemOUs.addQuery(field, true);
			grMemOUs.addAggregate('COUNT');
			grMemOUs.query();
			if(grMemOUs.next()){
				if (grMemOUs.getAggregate('COUNT') > 0){
					roleShoulbBeDeleted = false;
				} else
					roleShoulbBeDeleted = true;
			}
		}  

		// if no other records found, remove role
		//if (!grMemOUs.next()){
		if (roleShoulbBeDeleted ){ 
			var grRole = new GlideRecord('sys_user_has_role');
			grRole.addQuery('user', user_id);
			grRole.addQuery('role', role_id);
			grRole.query();
			if (grRole.next()) {
				grRole.deleteRecord();
				roleDeleted = true;
			}
		}
		return roleDeleted;
	},

	// STRY0124860 - called if groups are being used to manager permissions
	_removeUserFromGroup: function(user_id, field, role_name, role_type){
		var userRemovedFromGroup = false;
		var gr_userGroup = new GlideRecord('sys_user_grmember');
		var group_id = '';
		// 
		var msgUsesRoles = gs.getMessage("Tasker - The System Property [Uses Groups for Roles] is true,");
		var msgGroupNotDefined = gs.getMessage("Tasker - but a group is not defined for the System Property ");
		var msgPropertyName;
		gr_userGroup.initialize();
		switch(role_name){
			case "x_153465_discovert.tasker_application_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TASKER_APPLICATION_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_tasker_application_administrator_group]';
				break;
			case "x_153465_discovert.tasker_global_Tasking_Authority_member_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TASK_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_task_administrator_group]';
				break;
			case "x_153465_discovert.Task_Executive":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TASK_EXECUTIVE_GROUP;
				msgPropertyName = '[x_153465_discovert.role_task_executive_group]';
				break;
			case "x_153465_discovert.tasker_organizational_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_HIERARCHY_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_global_hierarchy_administrator_group]';
				break;
			case "x_153465_discovert.tasker_process_template_admin":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TEMPLATE_DESIGNER_PERMISSIONS_ADMINISTRATOR_GROUP;
				msgPropertyName = '[x_153465_discovert.role_template_designer_permissioins_administrator_group]';
				break;
			case "x_153465_discovert.tasker_process_template_global":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_GLOBAL_TEMPLATE_DESIGNER_GROUP;
				msgPropertyName = '[x_153465_discovert.role_global_template_designer_group]';
				break;
			case "x_153465_discovert.tasker_process_template_user":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_PERSONAL_TEMPLATE_DESIGNER_GROUP;
				msgPropertyName = '[x_153465_discovert.role_personal_template_designer_group]';
				break;
			case "x_153465_discovert.tasker_user":
				group_id = tasking_System_Settings_Scripts.CONST_ROLE_TAKSER_USER_GROUP;
				msgPropertyName = '[x_153465_discovert.role_tasker_user_group]';
				break;
			case "x_153465_discovert.tasker_single_ou_admin":
			case "x_153465_discovert.tasker_single_ou_member_admin":
			case "x_153465_discovert.tasker_process_template_ou":
			case "x_153465_discovert.tasker_hierarchy_import_user":
				// these global roles are no longer used
				return;
		}
		if(!group_id || group_id==""){
			msgUsesRoles = msgUsesRoles + msgGroupNotDefined + msgPropertyName;
			gs.error(msgUsesRoles);
		} else {
			// if the group id is in the system property, then add the record and return true
			gr_userGroup.addQuery('user', user_id);
			gr_userGroup.addQuery('group', group_id);
			gr_userGroup.query();
			if(gr_userGroup.next()){
				gr_userGroup.deleteRecord();
				userRemovedFromGroup = true;
			}
			userRemovedFromGroup = true;
		}
		return userRemovedFromGroup;
	},
	type: 'UserInfoScripts'
};
